import type { LLMCallEntity } from '@flusk/entities';

export interface TimeBucket {
  period: string;
  totalTokens: number;
  inputTokens: number;
  outputTokens: number;
  callCount: number;
}

export type TrendDirection = 'increasing' | 'decreasing' | 'stable';

export interface TokenTrendReport {
  granularity: 'hourly' | 'daily';
  buckets: TimeBucket[];
  trend: TrendDirection;
  changePercent: number;
}

function bucketKey(date: Date, granularity: 'hourly' | 'daily'): string {
  const iso = date.toISOString();
  return granularity === 'hourly' ? iso.slice(0, 13) : iso.slice(0, 10);
}

function detectTrend(values: number[]): { trend: TrendDirection; changePercent: number } {
  if (values.length < 2) return { trend: 'stable', changePercent: 0 };
  const half = Math.floor(values.length / 2);
  const firstHalf = values.slice(0, half);
  const secondHalf = values.slice(half);
  const avg1 = firstHalf.reduce((s, v) => s + v, 0) / firstHalf.length;
  const avg2 = secondHalf.reduce((s, v) => s + v, 0) / secondHalf.length;
  if (avg1 === 0) return { trend: avg2 > 0 ? 'increasing' : 'stable', changePercent: 0 };
  const change = ((avg2 - avg1) / avg1) * 100;
  const threshold = 15;
  const trend: TrendDirection = change > threshold ? 'increasing'
    : change < -threshold ? 'decreasing' : 'stable';
  return { trend, changePercent: Math.round(change * 10) / 10 };
}

export function tokenTrendAnalysis(
  calls: LLMCallEntity[],
  granularity: 'hourly' | 'daily' = 'daily',
): TokenTrendReport {
  const bucketMap = new Map<string, TimeBucket>();

  for (const c of calls) {
    const t = c.tokens as Record<string, number> | undefined;
    const key = bucketKey(new Date(c.createdAt as string), granularity);
    const bucket = bucketMap.get(key) ?? {
      period: key,
      totalTokens: 0,
      inputTokens: 0,
      outputTokens: 0,
      callCount: 0,
    };
    bucket.inputTokens += t?.input ?? 0;
    bucket.outputTokens += t?.output ?? 0;
    bucket.totalTokens += t?.total ?? (t?.input ?? 0) + (t?.output ?? 0);
    bucket.callCount += 1;
    bucketMap.set(key, bucket);
  }

  const buckets = [...bucketMap.values()]
    .sort((a, b) => a.period.localeCompare(b.period));

  const { trend, changePercent } = detectTrend(buckets.map(b => b.totalTokens));

  return { granularity, buckets, trend, changePercent };
}
